def cache_stats():
    cache_files = list(cache.cache_dir.glob('*.pkl'))
    meta_files = list(cache.cache_dir.glob('*.meta'))
    
    stats = {
        'total_entries': len(cache_files),
        'cache_dir': str(cache.cache_dir),
        'entries': []
    }
    
    for meta_file in meta_files:
        try:
            with open(meta_file, 'r') as f:
                metadata = json.load(f)
            
            time_remaining = max(0, metadata['expiration'] - time.time())
            
            stats['entries'].append({
                'key': metadata.get('key', 'unknown'),
                'created_at': metadata['created_at'],
                'ttl': metadata['ttl'],
                'expires_in': time_remaining,
                'expired': time_remaining == 0
            })
        except Exception:
            continue
    
    return jsonify(stats), 200


